Code.Terraform:
```hcl
# Service CatalogポートフォリオをAWS Organization内でのみ共有する
resource "aws_servicecatalog_portfolio_share" "<example_resource_name>" {
  portfolio_id = "<example_resource_id>"

  organization_node {           # 重大: AWS Organizations 内で共有
    type  = "ORGANIZATION"     # 組織全体とポートフォリオを共有します
    value = "<example_resource_id>"  # 例: o-xxxxxxxxxx
  }
}
```
